"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   articles: () => (/* binding */ articles),\n/* harmony export */   getArticleBySlug: () => (/* binding */ getArticleBySlug),\n/* harmony export */   getArticlesByCategory: () => (/* binding */ getArticlesByCategory),\n/* harmony export */   getFeaturedArticles: () => (/* binding */ getFeaturedArticles),\n/* harmony export */   getLatestArticles: () => (/* binding */ getLatestArticles),\n/* harmony export */   getRelatedArticles: () => (/* binding */ getRelatedArticles),\n/* harmony export */   searchArticles: () => (/* binding */ searchArticles)\n/* harmony export */ });\nconst articles = [\n    {\n        id: \"1\",\n        slug: \"sustainable-rice-farming-nigeria\",\n        title: \"Sustainable Rice Farming in Nigeria\",\n        excerpt: \"Discover how traditional methods combined with modern sustainable practices are revolutionizing rice farming in Nigeria.\",\n        content: `Rice farming in Nigeria has been transformed through the adoption of sustainable practices. At Oshanodes Agro, we believe that the future of agriculture lies in balancing productivity with environmental stewardship.\r\n\r\nOur approach combines traditional knowledge passed down through generations with innovative modern techniques. We use organic fertilizers, implement crop rotation, and practice water conservation to ensure soil health and long-term productivity.\r\n\r\nThe benefits are significant: improved soil quality, reduced chemical runoff, healthier crops, and better yields. More importantly, sustainable rice farming creates a positive impact on our communities and environment.`,\n        category: \"rice-farming\",\n        author: \"Engr. Fabian Orka\",\n        publishDate: \"2024-06-01\",\n        readingTime: 5,\n        image: \"/images/oshanodes 5.jpg\",\n        featured: true\n    },\n    {\n        id: \"3\",\n        slug: \"building-healthier-food-system\",\n        title: \"Building a Healthier Food System\",\n        excerpt: \"Exploring how sustainable agricultural practices contribute to food security, nutrition, and community health across West Africa.\",\n        content: `A healthier food system starts with how we grow food. Industrial agriculture prioritizes yield over quality, often at the expense of nutrition and environmental health.\r\n\r\nOshanodes Agro believes that sustainable agriculture creates nutritionally superior products. When we avoid synthetic pesticides and chemical fertilizers, our crops develop stronger nutritional profiles naturally.\r\n\r\nOur commitment to sustainability also ensures consistent food supply, reduces waste, and builds resilient farming communities. By investing in smallholder farmers and cooperative models, we're creating a food system that nourishes both people and the planet.\r\n\r\nThis is not just about individual products—it's about transforming the entire food system.`,\n        category: \"sustainability\",\n        author: \"Engr. Decent Emmanuel\",\n        publishDate: \"2024-05-20\",\n        readingTime: 7,\n        image: \"/images/oshanodes 3.jpg\"\n    },\n    {\n        id: \"4\",\n        slug: \"future-sustainable-agriculture\",\n        title: \"The Future of Sustainable Agriculture\",\n        excerpt: \"Technology, innovation, and commitment to environmental stewardship are shaping the next generation of farming practices.\",\n        content: `The future of agriculture is sustainable, data-driven, and community-centered. At Oshanodes Agro, we're embracing emerging technologies while maintaining core sustainable principles.\r\n\r\nPrecision agriculture tools help us optimize water usage, monitor soil health in real-time, and predict yield outcomes. Blockchain technology enables supply chain transparency, allowing customers to trace products back to the farm.\r\n\r\nBut technology alone isn't enough. The future requires stronger partnerships between farmers, researchers, government, and consumers. It demands investment in farmer education and cooperative models that benefit small-scale producers.\r\n\r\nWe're committed to being leaders in this transformation, proving that agriculture can be profitable, sustainable, and regenerative.`,\n        category: \"agricultural-tips\",\n        author: \"Oshanodes Team\",\n        publishDate: \"2024-05-15\",\n        readingTime: 8,\n        image: \"/images/oshanodes 6.jpg\"\n    },\n    {\n        id: \"5\",\n        slug: \"oshanodes-expansion-announcement\",\n        title: \"Oshanodes Agro Expansion Announcement\",\n        excerpt: \"We're thrilled to announce our expansion into three new farming regions across the Benue Valley, creating new opportunities for farmers and customers.\",\n        content: `We are excited to announce a major expansion of Oshanodes Agro operations. Starting this season, we are establishing farming operations in three new regions within the Benue Valley.\r\n\r\nThis expansion represents our commitment to scaling sustainable agriculture while creating economic opportunities for local farming communities. Each new region will employ 50+ farmers and create value-added processing jobs.\r\n\r\nThe expansion includes investment in modern processing facilities, farmer training programs, and community development initiatives. We expect to increase our rice and bean production by 40% while maintaining our strict quality and sustainability standards.\r\n\r\nThis growth positions Oshanodes Agro to serve more customers across West Africa while deepening our positive community impact.`,\n        category: \"company-news\",\n        author: \"Oshanodes Communications\",\n        publishDate: \"2024-06-10\",\n        readingTime: 4,\n        image: \"/images/oshanodes 7.jpg\"\n    },\n    {\n        id: \"6\",\n        slug: \"farmers-cooperative-success-story\",\n        title: \"Farmers Cooperative Success Story\",\n        excerpt: \"Meet the smallholder farmers in the Benue Valley whose lives have been transformed through our cooperative farming model.\",\n        content: `Maria and her neighbors have been farming rice and beans for generations, but it wasn't until joining the Oshanodes cooperative that their lives truly transformed.\r\n\r\nThrough the cooperative model, small farmers gain access to modern tools, training, and fair market prices. Instead of selling to middlemen at low prices, cooperative members sell directly to Oshanodes at rates that fairly compensate their work.\r\n\r\nThe cooperative also provides education on sustainable farming, soil management, and post-harvest handling. Members share equipment and knowledge, reducing individual costs while improving outcomes.\r\n\r\nOver the past two years, Maria has doubled her harvest while reducing her input costs. She's invested in her children's education and improved her family's home. Her story is just one of hundreds in the Oshanodes cooperative network.`,\n        category: \"community-stories\",\n        author: \"Engr. Logan Thewis\",\n        publishDate: \"2024-05-10\",\n        readingTime: 5,\n        image: \"/images/oshanodes 8.jpg\"\n    },\n    {\n        id: \"7\",\n        slug: \"organic-soil-management-guide\",\n        title: \"Organic Soil Management Guide\",\n        excerpt: \"A practical guide to improving soil health through organic practices, reducing chemical inputs while increasing productivity.\",\n        content: `Healthy soil is the foundation of productive agriculture. At Oshanodes Agro, we invest heavily in soil management because we know that soil health directly impacts crop quality and yield.\r\n\r\nOrganic soil management practices include:\r\n- Crop rotation to prevent soil depletion\r\n- Composting and organic matter addition\r\n- Reduced or no-till farming\r\n- Cover cropping\r\n- Biological pest management\r\n\r\nThese practices rebuild soil structure, increase water retention, and enhance beneficial microorganism activity. The result is more resilient crops that require fewer external inputs.\r\n\r\nImplementing these practices requires initial investment and patience, but the long-term benefits justify the transition.`,\n        category: \"agricultural-tips\",\n        author: \"Engr. Elijah Oga\",\n        publishDate: \"2024-04-28\",\n        readingTime: 6,\n        image: \"/images/oshanodes 11.jpg\"\n    },\n    {\n        id: \"8\",\n        slug: \"water-conservation-rice-farming\",\n        title: \"Water Conservation in Rice Farming\",\n        excerpt: \"Innovative irrigation techniques that reduce water usage by 40% while maintaining optimal yields in rice production.\",\n        content: `Rice farming traditionally requires significant water resources. However, innovative irrigation techniques can substantially reduce water usage while maintaining crop health.\r\n\r\nDrip irrigation systems deliver water directly to plant roots, reducing evaporation and runoff. Alternate wetting and drying (AWD) techniques allow soil to dry between waterings, encouraging deeper root development while conserving water.\r\n\r\nAt Oshanodes Agro, we've implemented these techniques across our operations, reducing water usage by 40% compared to traditional flooding methods. This has particular importance as water scarcity becomes an increasing challenge.\r\n\r\nThese practices benefit both our bottom line and the environment.`,\n        category: \"sustainability\",\n        author: \"DR. Isreal Peter\",\n        publishDate: \"2024-04-15\",\n        readingTime: 5,\n        image: \"/images/oshanodes 10.jpg\"\n    },\n    {\n        id: \"10\",\n        slug: \"women-farming-leadership\",\n        title: \"Women in Agriculture Leadership\",\n        excerpt: \"Celebrating the women farmers and agricultural leaders driving innovation and sustainability in West African farming.\",\n        content: `Women play a critical role in agriculture, yet often face unique challenges in access to resources, credit, and market opportunities. At Oshanodes Agro, we're committed to empowering women farmers.\r\n\r\nOur initiatives include:\r\n- Women-focused training programs\r\n- Access to credit and equipment financing\r\n- Women's farmer cooperatives\r\n- Leadership development\r\n- Fair pricing and guaranteed markets\r\n\r\nWomen bring innovation, resilience, and community focus to agriculture. When we empower women farmers, we create positive ripple effects across entire communities.\r\n\r\nThe women in our network are proof that gender equity and agricultural success go hand-in-hand.`,\n        category: \"community-stories\",\n        author: \"miss. Loved\",\n        publishDate: \"2024-03-28\",\n        readingTime: 5,\n        image: \"/images/oshanodes 13.jpg\"\n    },\n    {\n        id: \"11\",\n        slug: \"climate-resilient-farming\",\n        title: \"Climate-Resilient Farming Practices\",\n        excerpt: \"Adapting farming practices to build resilience against changing climate patterns while maintaining productivity.\",\n        content: `Climate change poses significant challenges to agriculture. Building resilience requires diverse strategies and adaptive management.\r\n\r\nClimate-resilient practices include:\r\n- Diversified crop production\r\n- Water harvesting and storage\r\n- Improved seed varieties\r\n- Mulching and soil conservation\r\n- Forest integration (agroforestry)\r\n\r\nThese practices reduce vulnerability to drought, flooding, and temperature extremes. At Oshanodes Agro, we're investing in climate adaptation to ensure long-term productivity and farmer livelihoods.\r\n\r\nOur commitment to resilience benefits farmers, consumers, and the planet.`,\n        category: \"sustainability\",\n        author: \"miss. Loved\",\n        publishDate: \"2024-03-15\",\n        readingTime: 7,\n        image: \"/images/oshanodes 14.jpg\"\n    },\n    {\n        id: \"12\",\n        slug: \"customer-testimonial-feature\",\n        title: \"Customer Impact: Why Families Choose Oshanodes\",\n        excerpt: \"Hear from families across West Africa about how Oshanodes Agro products have impacted their health and communities.\",\n        content: `Customer stories remind us why we do what we do. Here's what customers are saying:\r\n\r\n\"Since switching to Oshanodes rice, my family feels healthier. The taste is noticeably different from mass-produced alternatives.\" - Ama, Ghana\r\n\r\n\"I love knowing exactly where my food comes from. I can trust that Oshanodes rice and beans are grown responsibly.\" - Hassan, Nigeria\r\n\r\n\"As a restaurant owner, Oshanodes products elevate my dishes. My customers notice the quality difference.\" - Zainab, Benin\r\n\r\nThese testimonials reflect our core mission: producing food that nourishes people and communities. Every purchase of Oshanodes products supports sustainable farming and rural development.\r\n\r\nWe're grateful for our customers' trust and commitment to better agriculture.`,\n        category: \"company-news\",\n        author: \"Oshanodes Team\",\n        publishDate: \"2024-03-01\",\n        readingTime: 4,\n        image: \"/images/oshanodes 5.jpg\",\n        featured: true\n    }\n];\nfunction getArticleBySlug(slug) {\n    return articles.find((article)=>article.slug === slug);\n}\nfunction getArticlesByCategory(category) {\n    return articles.filter((article)=>article.category === category);\n}\nfunction getRelatedArticles(slug, limit = 3) {\n    const article = getArticleBySlug(slug);\n    if (!article) return [];\n    return articles.filter((a)=>a.slug !== slug && a.category === article.category).slice(0, limit);\n}\nfunction getFeaturedArticles(limit = 2) {\n    return articles.filter((a)=>a.featured).slice(0, limit);\n}\nfunction searchArticles(query) {\n    const q = query.toLowerCase();\n    return articles.filter((a)=>a.title.toLowerCase().includes(q) || a.excerpt.toLowerCase().includes(q) || a.content.toLowerCase().includes(q));\n}\nfunction getLatestArticles(limit = 3) {\n    return [\n        ...articles\n    ].sort((a, b)=>new Date(b.publishDate).getTime() - new Date(a.publishDate).getTime()).slice(0, limit);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/data/articles.ts\n");

